#include <stdint.h>



int main(void)
{

	uint32_t *pClockReg = (uint32_t*)0x40023830;//address of clock control register(AHB1ENR)
	uint32_t *pPortDModeReg = (uint32_t*)0x40020C00;//address of the GPIOD mode register used to control mode
	uint32_t *pPortOutputReg = (uint32_t*)0x40020C14;//address of the GPIOD output data register used to write

	//enable the clock for GPIOD in the AHB1ENR
	*pClockReg |= (1 << 3);
	//configure the mode of the IO pin as output
	*pPortDModeReg &= ~(3 << (12 * 2));
	*pPortDModeReg |= (1 <<  (12 * 2));
//	*pPortOutputReg |= 0;
	//set 12th bit of the output data register to make IO pin as high
	while(1){
		*pPortOutputReg |= (1 << 12);

		//small human observable delay
		for(uint32_t i =0;i<10000;i++);

		// turn off LED
		*pPortOutputReg &= ~(1<<12);

		for(uint32_t i =0;i<10000;i++);
	}

    /* Loop forever */
	for(;;);
}
